import React, {useState} from 'react'
import {getMonth} from "../../helpers/getMonth";

export const UpdateRow = ({update, currency}) => {

    const [edit, setEdit] = useState(false);

    const {year, month, value} = update

    const showInput = () => {
        setEdit(true)
    }

    const hideInput = () => {
        setEdit(false)
    }

    return (
        <tr>
            <td>{year}</td>
            <td>{getMonth(month)}</td>
            {
                edit
                    ?
                        <td className="align-right">
                            <form>
                                <input value={value} className="account__update-input" name="value" />
                                <button type="submit" className="btn btn-success ml-1">Save</button>
                                <a className="btn btn-danger ml-1" onClick={hideInput}>Cancel</a>
                            </form>
                        </td>

                    :
                        <td className="align-right">
                            {value} <small>{currency} </small>
                            <svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" fill="currentColor"
                                 className="bi bi-pencil-fill ml-3" viewBox="0 0 16 16" onClick={showInput}>
                                <path
                                    d="M12.854.146a.5.5 0 0 0-.707 0L10.5 1.793 14.207 5.5l1.647-1.646a.5.5 0 0 0 0-.708l-3-3zm.646 6.061L9.793 2.5 3.293 9H3.5a.5.5 0 0 1 .5.5v.5h.5a.5.5 0 0 1 .5.5v.5h.5a.5.5 0 0 1 .5.5v.5h.5a.5.5 0 0 1 .5.5v.207l6.5-6.5zm-7.468 7.468A.5.5 0 0 1 6 13.5V13h-.5a.5.5 0 0 1-.5-.5V12h-.5a.5.5 0 0 1-.5-.5V11h-.5a.5.5 0 0 1-.5-.5V10h-.5a.499.499 0 0 1-.175-.032l-.179.178a.5.5 0 0 0-.11.168l-2 5a.5.5 0 0 0 .65.65l5-2a.5.5 0 0 0 .168-.11l.178-.178z"/>
                            </svg>
                        </td>
            }

        </tr>
    )
}